1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_THRESHOLD = 2;
4	const LOYALTY_DISCOUNT = 0.2;
5	const FOLLOWUP_DISCOUNT = 0.15;
6	
7	interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	interface Damage {
20	  itemType: string;
21	  amount: number;
22	}
23	
24	interface ClaimStep {
25	  op: "claim";
26	  policy: number;
27	  incident: { cause: string; damages: Damage[] };
28	}
29	
30	type Step = QuoteStep | ClaimStep;
31	
32	interface Customer {
33	  yearsWithMHPCO: number;
34	}
35	
36	interface Scenario {
37	  customer: Customer;
38	  steps: Step[];
39	}
40	
41	interface QuoteResult {
42	  premium: number;
43	}
44	
45	interface ClaimResult {
46	  payout: number;
47	  remainingCap: number;
48	}
49	
50	type StepResult = QuoteResult | ClaimResult;
51	
52	const COMPONENT_BASE_PREMIUM = 25;
53	const COMPONENT_INSURANCE_VALUE = 250;
54	const DEDUCTIBLE = 100;
55	const CAP_MULTIPLIER = 2;
56	
57	const BASE_PREMIUMS: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	  rune: COMPONENT_BASE_PREMIUM,
63	  moonstone: COMPONENT_BASE_PREMIUM,
64	};
65	
66	const INSURANCE_VALUES: Record<string, number> = {
67	  sword: 1000,
68	  amulet: 600,
69	  staff: 800,
70	  potion: 400,
71	  rune: COMPONENT_INSURANCE_VALUE,
72	  moonstone: COMPONENT_INSURANCE_VALUE,
73	};
74	
75	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
76	const BLOCK_SIZE = 3;
77	const BLOCK_PREMIUM = 60;
78	
79	const formsBlock = (type: string, count: number): boolean =>
80	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
81	
82	const typeBasePremium = (type: string, count: number): number => {
83	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
84	  return count * BASE_PREMIUMS[type];
85	};
86	
87	// Tallies a collection into a count-by-key map, given how to read each
88	// element's key. Used to count both insured items and reported damages by type.
89	const tallyBy = <T>(elements: T[], keyOf: (element: T) => string): Map<string, number> =>
90	  elements.reduce((counts, element) => {
91	    const key = keyOf(element);
92	    return counts.set(key, (counts.get(key) ?? 0) + 1);
93	  }, new Map<string, number>());
94	
95	// Totals a collection by reading a number off each element. Used wherever a
96	// per-item amount (insurance value, surcharge) is summed across the policy.
97	const sumOf = <T>(elements: T[], amountOf: (element: T) => number): number =>
98	  elements.reduce((total, element) => total + amountOf(element), 0);
99	
100	const countByType = (items: Item[]): Map<string, number> =>
101	  tallyBy(items, (item) => item.type);
102	
103	const policyBasePremium = (items: Item[]): number =>
104	  [...countByType(items)].reduce(
105	    (base, [type, count]) => base + typeBasePremium(type, count),
106	    0,
107	  );
108	
109	// A rate rule contributes its rate to a subject only when it applies.
110	interface RateRule<T> {
111	  applies: (subject: T) => boolean;
112	  rate: number;
113	}
114	
115	const sumApplicableRates = <T>(rules: RateRule<T>[], subject: T): number =>
116	  rules.reduce(
117	    (rate, rule) => (rule.applies(subject) ? rate + rule.rate : rate),
118	    0,
119	  );
120	
121	const CURSE_SURCHARGE = 0.5;
122	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
123	const HIGH_ENCHANTMENT_THRESHOLD = 5;
124	
125	const SURCHARGE_RULES: RateRule<Item>[] = [
126	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
127	  {
128	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
129	    rate: HIGH_ENCHANTMENT_SURCHARGE,
130	  },
131	];
132	
133	const itemSurcharge = (item: Item): number =>
134	  sumApplicableRates(SURCHARGE_RULES, item) * BASE_PREMIUMS[item.type];
135	
136	const itemSurcharges = (items: Item[]): number =>
137	  sumOf(items, itemSurcharge);
138	
139	interface PolicyContext {
140	  customer: Customer;
141	  isFollowUp: boolean;
142	}
143	
144	// Policy-wide modifiers each apply a signed rate to the policy base:
145	// positive rates are surcharges, negative rates are discounts.
146	const POLICY_MODIFIER_RULES: RateRule<PolicyContext>[] = [
147	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
148	  {
149	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
150	    rate: -LOYALTY_DISCOUNT,
151	  },
152	  { applies: ({ isFollowUp }) => isFollowUp, rate: -FOLLOWUP_DISCOUNT },
153	];
154	
155	const policyModifierRate = (context: PolicyContext): number =>
156	  sumApplicableRates(POLICY_MODIFIER_RULES, context);
157	
158	// A signed modifier rate scales a base: positive rates surcharge, negative discount.
159	const applyModifierRate = (base: number, rate: number): number =>
160	  base * (1 + rate);
161	
162	// Strips floating-point error that could nudge an exact value over an
163	// integer boundary, so the rounding below acts on the intended amount.
164	const cleanFloatNoise = (amount: number): number => Number(amount.toFixed(6));
165	
166	// Premiums round up, payouts round down — both in the MHPCO's favor.
167	const roundUpPremium = (amount: number): number =>
168	  Math.ceil(cleanFloatNoise(amount));
169	
170	const roundDownPayout = (amount: number): number =>
171	  Math.floor(cleanFloatNoise(amount));
172	
173	// The MHPCO only insures the item types it has published a base premium for.
174	const isInsurableType = (type: string): boolean => type in BASE_PREMIUMS;
175	
176	// Every quoted item must be a type the MHPCO actually insures.
177	const assertKnownItems = (items: Item[]): void => {
178	  for (const item of items) {
179	    if (!isInsurableType(item.type)) {
180	      throw new Error(`unknown item type: ${item.type}`);
181	    }
182	  }
183	};
184	
185	const quotePremium = (items: Item[], context: PolicyContext): number => {
186	  const policyBase = policyBasePremium(items);
187	  const modifierRate = policyModifierRate(context);
188	  // Policy modifiers scale the policy base only; item surcharges are added
189	  // separately (outside the modifier scope), then the flat fee comes last.
190	  const modifiedPolicyBase = applyModifierRate(policyBase, modifierRate);
191	  const total = modifiedPolicyBase + itemSurcharges(items) + PROCESSING_FEE;
192	  return roundUpPremium(total);
193	};
194	
195	const insuranceSum = (items: Item[]): number =>
196	  sumOf(items, (item) => INSURANCE_VALUES[item.type]);
197	
198	// A policy's payout cap is twice its total insured value.
199	const policyCap = (items: Item[]): number =>
200	  CAP_MULTIPLIER * insuranceSum(items);
201	
202	interface Policy {
203	  items: Item[];
204	  remainingCap: number;
205	}
206	
207	// A freshly registered policy starts with its full cap available to claim.
208	const newPolicy = (items: Item[]): Policy => ({
209	  items,
210	  remainingCap: policyCap(items),
211	});
212	
213	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
214	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
215	
216	const qualifiesForHalfReimbursement = (item: Item): boolean =>
217	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
218	
219	// The spec names two reimbursement clauses. The high-enchantment clause
220	// (enchantment >= 8) reimburses 50%; the dragon-material clause reimburses
221	// 100%. When both apply, 50% wins — the lower payout. Since 100% reimbursement
222	// is identical to the default (full) reimbursement, the dragon clause needs no
223	// branch of its own: it changes nothing the default doesn't already do, and the
224	// "50% wins" interaction falls out naturally from preferring the half clause
225	// here. A dedicated dragon branch would be a no-op the tests can't distinguish.
226	const reimbursement = (item: Item, amount: number): number =>
227	  qualifiesForHalfReimbursement(item)
228	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE * amount
229	    : amount;
230	
231	// The damaged item is the policy item whose type the damage names. The lookup
232	// always succeeds here because assertDamagesCovered has already rejected any
233	// claim naming a type the policy doesn't insure (insured count 0), so by this
234	// point every damage references an insured type.
235	const insuredItemFor = (damage: Damage, policy: Policy): Item =>
236	  policy.items.find((item) => item.type === damage.itemType)!;
237	
238	const damagePayout = (damage: Damage, policy: Policy): number =>
239	  reimbursement(insuredItemFor(damage, policy), damage.amount) - DEDUCTIBLE;
240	
241	// Each damage carries its own deductible, so the requested payout is the sum
242	// of per-damage payouts — not the deductible applied once to the total.
243	const requestedPayout = (step: ClaimStep, policy: Policy): number =>
244	  step.incident.damages.reduce(
245	    (sum, damage) => sum + damagePayout(damage, policy),
246	    0,
247	  );
248	
249	// A claim may not report more damages of a type than the policy insures of
250	// that type — there is no insured item left to attribute the extra damage to.
251	// A type the policy doesn't insure at all has an insured count of 0, so this
252	// same check also rejects claims referencing items that aren't in the policy.
253	const assertDamagesCovered = (step: ClaimStep, policy: Policy): void => {
254	  const insured = countByType(policy.items);
255	  const damaged = tallyBy(step.incident.damages, (damage) => damage.itemType);
256	  for (const [itemType, count] of damaged) {
257	    const insuredCount = insured.get(itemType) ?? 0;
258	    if (count > insuredCount) {
259	      throw new Error(
260	        `claim reports ${count} ${itemType} damage(s) but policy insures ${insuredCount}`,
261	      );
262	    }
263	  }
264	};
265	
266	// A damage cannot reduce the insured value by a negative amount.
267	const assertNonNegativeDamages = (step: ClaimStep): void => {
268	  for (const damage of step.incident.damages) {
269	    if (damage.amount < 0) {
270	      throw new Error(`damage amount must not be negative: ${damage.amount}`);
271	    }
272	  }
273	};
274	
275	const settleClaim = (step: ClaimStep, policy: Policy): ClaimResult => {
276	  // Reject invalid claims before computing any payout. These are two distinct
277	  // rules — no negative amounts, and no more damages of a type than insured —
278	  // kept as separately named checks so the call site names what each rejects.
279	  assertNonNegativeDamages(step);
280	  assertDamagesCovered(step, policy);
281	  // The payout can never exceed what's left of the cap, and each settlement
282	  // spends down that remainder — so successive claims against the same policy
283	  // draw from a shrinking cap until it's exhausted.
284	  const payout = Math.min(
285	    roundDownPayout(requestedPayout(step, policy)),
286	    policy.remainingCap,
287	  );
288	  policy.remainingCap -= payout;
289	  return { payout, remainingCap: policy.remainingCap };
290	};
291	
292	// Steps are processed in order against accumulating state: each quote
293	// registers a policy (keyed by its step index) and marks that a prior
294	// quote exists, so later quotes count as follow-ups; each claim settles
295	// against an already-registered policy. The sequential state-building is
296	// why this is an explicit loop rather than a (pure) map.
297	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
298	  const policies = new Map<number, Policy>();
299	  let hasPriorQuote = false;
300	  const results: StepResult[] = [];
301	
302	  scenario.steps.forEach((step, index) => {
303	    if (step.op === "claim") {
304	      const policy = policies.get(step.policy)!;
305	      results.push(settleClaim(step, policy));
306	    } else {
307	      const context: PolicyContext = {
308	        customer: scenario.customer,
309	        isFollowUp: hasPriorQuote,
310	      };
311	      hasPriorQuote = true;
312	      assertKnownItems(step.items);
313	      policies.set(index, newPolicy(step.items));
314	      results.push({ premium: quotePremium(step.items, context) });
315	    }
316	  });
317	
318	  return { results };
319	};
